// // This module reads the state of a GPIO pin and outputs a signal indicating whether the pin is low or high. It has a reset signal that sets the output to high. The GPIO pin state is read on the falling edge of a clock signal.
module gpio_controller(  
    input wire clk,  
    input wire reset,  
    input wire gpio_pin,  
    output reg gpio_status  
);  
    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            gpio_status <= 1'b0;  
        end else begin  
            gpio_status <= gpio_pin;  
        end  
    end  
endmodule
